#include <vector>
#include <algorithm>
#include <iostream>

using namespace std;

class Solution {
public:
    long long solve(std::vector<long long> nums, long long k) {
        int n = nums.size();
        if (n == 0) return 0;

        // dp[i][0] = maximum score of a valid alternating subsequence ending at index i, where nums[i] is the *smaller* element 
        // relative to its predecessor (i.e., the pattern ends in ... > nums[i])
        // dp[i][1] = maximum score of a valid alternating subsequence ending at index i, where nums[i] is the *larger* element 
        // relative to its predecessor (i.e., the pattern ends in ... < nums[i])

        // Since the length 1 subsequence is always valid, initialize dp[i][0] and dp[i][1] to nums[i] for all i.
        // A length 1 sequence can be considered both a 'smaller' and a 'larger' endpoint depending on how we define the state transition, 
        // but initializing to nums[i] correctly handles the base case.

        // Let's refine the DP state:
        // dp[i][0]: Max score of an alternating subsequence ending at index i, where the last transition was DOWN (i.e., nums[i-1] > nums[i] if it was longer than 1, or it's the first element).
        // dp[i][1]: Max score of an alternating subsequence ending at index i, where the last transition was UP (i.e., nums[i-1] < nums[i] if it was longer than 1, or it's the first element).

        // If length is 1 (nums[i]), it can be seen as starting both an UP or a DOWN sequence.

        vector<vector<long long>> dp(n, vector<long long>(2, 0));
        long long max_score = 0;

        for (int i = 0; i < n; ++i) {
            // Base case: Subsequence of length 1 ending at i
            dp[i][0] = nums[i]; // Can be a start of a sequence
            dp[i][1] = nums[i]; // Can be a start of a sequence

            // Transition: Look back at all j < i such that i - j >= k
            for (int j = 0; j <= i - k; ++j) {
                // Case 1: Current transition is DOWN (nums[j] > nums[i]). 
                // The subsequence ending at j must have ended in an UP transition (dp[j][1]).
                if (nums[j] > nums[i]) {
                    // New score = Score ending at j (must end UP) + nums[i]
                    dp[i][0] = max(dp[i][0], dp[j][1] + nums[i]);
                }

                // Case 2: Current transition is UP (nums[j] < nums[i]).
                // The subsequence ending at j must have ended in a DOWN transition (dp[j][0]).
                if (nums[j] < nums[i]) {
                    // New score = Score ending at j (must end DOWN) + nums[i]
                    dp[i][1] = max(dp[i][1], dp[j][0] + nums[i]);
                }
            }

            // Update overall maximum score
            max_score = max({max_score, dp[i][0], dp[i][1]});
        }

        return max_score;
    }
};
