    long long solve(std::vector<long long> nums, long long k) {
        int n = nums.size();
        if (n == 0) {
            return 0;
        }

        // dp[i][0]: Maximum score of a valid alternating subsequence ending at index i,
        // where the sequence ends with a value that is *smaller* than the previous element (i.e., ... > nums[i]).
        // This corresponds to the last transition being a '<' if the length is even, or a '>' if the length is odd,
        // depending on the starting pattern. More precisely, if we denote the required pattern as:
        // Start with '<': a1 < a2 > a3 < a4 ...
        // Start with '>': a1 > a2 < a3 > a4 ...

        // Let's simplify the state based on the required relationship with the *previous* element.
        // dp[i][0]: Max score of a valid subsequence ending at i, where nums[i] must be SMALLER than the previous element. (i.e., prev > nums[i])
        // dp[i][1]: Max score of a valid subsequence ending at i, where nums[i] must be LARGER than the previous element. (i.e., prev < nums[i])

        // Since the sequence must be strictly alternating, if the sequence ends with nums[i] and the previous element was nums[j] (j < i, i - j >= k):
        // 1. If nums[j] > nums[i], then the previous transition (ending at j) must have required nums[j] < nums[prev_to_j].
        // 2. If nums[j] < nums[i], then the previous transition (ending at j) must have required nums[j] > nums[prev_to_j].

        // Let dp[i][0] be the max score ending at i, where nums[i] is the "valley" (smaller than the previous element).
        // Let dp[i][1] be the max score ending at i, where nums[i] is the "peak" (larger than the previous element).

        // Base case: A sequence of length 1 always satisfies the condition. Score is nums[i].
        // For length 1, it can be considered either a peak or a valley, we initialize both to nums[i].

        vector<vector<long long>> dp(n, vector<long long>(2, 0));
        long long max_score = 0;

        for (int i = 0; i < n; ++i) {
            // Initialize for length 1 subsequence
            dp[i][0] = nums[i]; // Can be a valley (or start)
            dp[i][1] = nums[i]; // Can be a peak (or start)

            // Search for a preceding element j
            for (int j = 0; j <= i - k; ++j) {
                // Transition from j to i

                // Case 1: nums[j] > nums[i]. Sequence ends with ... > nums[i]. nums[i] is a "valley".
                // For this to be valid, the sequence ending at j must have had nums[j] as a "peak" (dp[j][1]), 
