                if (nums[j] > nums[i]) {
                    // We extend the sequence ending at j where j was a peak (dp[j][1])
                    dp[i][0] = max(dp[i][0], dp[j][1] + nums[i]);
                }

                // Case 2: nums[j] < nums[i]. Sequence ends with ... < nums[i]. nums[i] is a "peak".
                // For this to be valid, the sequence ending at j must have had nums[j] as a "valley" (dp[j][0]), 
                // because the alternation requires: ... > nums[j] < nums[i].
                if (nums[j] < nums[i]) {
                    // We extend the sequence ending at j where j was a valley (dp[j][0])
                    dp[i][1] = max(dp[i][1], dp[j][0] + nums[i]);
                }
            }

            // Update overall maximum score
            max_score = max({max_score, dp[i][0], dp[i][1]});
        }

        return max_score;
    }
