using namespace std;

// Since the constraints are up to 10^5, an O(N^2) DP will TLE.
// We need a more efficient DP, likely O(N*C) or O(N log N), where C is small or constant.

/**
 * The problem asks for the maximum sum of a subsequence satisfying two conditions:
 * 1. Index difference: i_{t+1} - i_t >= k for all adjacent elements in the subsequence.
 * 2. Alternating property: The sequence must be strictly alternating (up-down-up... or down-up-down...).
 *
 * This is a dynamic programming problem.
 * Let dp[i][state] be the maximum score of a valid subsequence ending at index i,
 * where 'state' describes the relationship between nums[i] and the previous element.
 *
 * State definitions for dp[i]:
 * - dp[i][0]: Max score ending at i, where nums[i] is the first element (length 1).
 * - dp[i][1]: Max score ending at i, where the sequence is currently increasing (i.e., nums[prev] < nums[i]).
 * - dp[i][2]: Max score ending at i, where the sequence is currently decreasing (i.e., nums[prev] > nums[i]).
 *
 * Base Case: For any i, dp[i][0] = nums[i] (subsequence of length 1).
 *
 * Transition: To calculate dp[i][state], we look at all possible previous indices j < i - k.
 *
 * 1. Increasing (nums[j] < nums[i]):
 *    The previous state at j must have been decreasing (dp[j][2]) or it was the start (dp[j][0]).
 *    dp[i][1] = nums[i] + max(
 *        max(dp[j][2]) for j <= i - k and nums[j] < nums[i],
 *        max(dp[j][0]) for j <= i - k and nums[j] < nums[i]  // This case is implicitly covered if we handle the starting point correctly
 *    )
 *
 * 2. Decreasing (nums[j] > nums[i]):
 *    The previous state at j must have been increasing (dp[j][1]) or it was the start (dp[j][0]).
 *    dp[i][2] = nums[i] + max(
 *        max(dp[j][1]) for j <= i - k and nums[j] > nums[i],
 *        max(dp[j][0]) for j <= i - k and nums[j] > nums[i]
 *    )
 *
 * Re-evaluating the states to simplify transitions:
 * Let dp_up[i] be the max score ending at i, where the sequence is *currently* going up (i.e., nums[i] > nums[prev]).
 * Let dp_down[i] be the max score ending at i, where the sequence is *currently* going down (i.e., nums[i] < nums[prev]).
 *
 * For length 1: The score is nums[i]. This can transition into both UP and DOWN if it's followed by an element.
 *
 * Initialization:
 * dp_up[i] = nums[i]
 * dp_down[i] = nums[i]
 *
 * Transition for i from 0 to n-1:
 * For all j such that 0 <= j <= i - k:
 *
 * 1. Calculating dp_up[i] (nums[i] > nums[j]):
 *    The previous element at j must have ended a sequence going down (dp_down[j]) or it was the start (nums[j]).
 *    dp_up[i] = max(dp_up[i], nums[i] + max(dp_down[j], nums[j]))  if nums[i] > nums[j]
 *
 * 2. Calculating dp_down[i] (nums[i] < nums[j]):
 *    The previous element at j must have ended a sequence going up (dp_up[j]) or it was the start (nums[j]).
 *    dp_down[i] = max(dp_down[i], nums[i] + max(dp_up[j], nums[j])) if nums[i] < nums[j]
 *
 * Note on starting sequence: A length 1 sequence [nums[i]] has score nums[i]. It can transition to an UP sequence if the next element is larger, or a DOWN sequence if the next element is smaller.
 * If we use the formulation above, we must ensure the base case (length 1) is covered.
 * If we set dp_up[i] = nums[i] and dp_down[i] = nums[i], this covers the length 1 case.
 *
 * If dp_down[j] is the max score ending at j with a down swing, adding nums[i] (where nums[i] > nums[j]) makes it an UP swing.
 * The base case for the UP swing transition must be the score of the single element sequence ending at j, which is nums[j].
 *
 * Corrected Transition Logic:
 * For i = 0 to n-1:
 *   dp_up[i] = nums[i]
 *   dp_down[i] = nums[i]
 *
 *   For j = 0 to i - k:
 *     if nums[i] > nums[j]: // Potential UP swing ending at i
 *       // Previous must have been DOWN swing ending at j, OR just the element at j (start of sequence)
 *       dp_up[i] = max(dp_up[i], nums[i] + max(dp_down[j], nums[j]))
 *
 *     if nums[i] < nums[j]: // Potential DOWN swing ending at i
 *       // Previous must have been UP swing ending at j, OR just the element at j (start of sequence)
 *       dp_down[i] = max(dp_down[i], nums[i] + max(dp_up[j], nums[j]))
 *
 * Complexity: O(N * (N-K)) = O(N^2). Given N=10^5, this is too slow.
 *
 * Optimization:
 * We need to efficiently find:
 * 1. max(dp_down[j], nums[j]) for j <= i - k and nums[j] < nums[i]
 * 2. max(dp_up[j], nums[j]) for j <= i - k and nums[j] > nums[i]
 *
 * This is a 2D range maximum query problem: one dimension is index (j <= i-k), the other is value (nums[j] < X or nums[j] > X).
 * Since the index constraint (j <= i-k) is monotonically increasing as i increases, we can process it incrementally.
 * The value constraint suggests using a data structure indexed by value, like a Fenwick Tree (BIT) or Segment Tree.
 *
 * Since values are up to 10^5, we can use a coordinate compression or directly use the value as an index if $V_{max} = 10^5$.
 *
 * Let $V_{max} = 10^5$. We need two BITs/Segment Trees:
 * 1. $\text{BIT}_{\text{down}}$: Stores $\max(\text{dp\_down}[j], \text{nums}[j])$ indexed by $\text{nums}[j]$, but only considering $j \le i-k$.
 * 2. $\text{BIT}_{\text{up}}$: Stores $\max(\text{dp\_up}[j], \text{nums}[j])$ indexed by $\text{nums}[j]$, but only considering $j \le i-k$.
 *
 * When processing index $i$:
 * 1. Look up required maximums from BITs for $j \le i-k$.
 * 2. Calculate $\text{dp\_up}[i]$ and $\text{dp\_down}[i]$.
 * 3. Update BITs with values corresponding to index $i$. This update only happens when $i$ becomes a valid $j$ for future $i' > i+k$.
 *
 * The index constraint $j \le i-k$ makes standard incremental BIT updates tricky because we need to "commit" data from index $j$ to the data structure at time $i-k$.
 *
 * We can maintain a sliding window or a set of structures, but since we only query up to $i-k$, we can use a structure that only contains valid past indices.
 *
 * Strategy:
 * Iterate $i$ from $0$ to $N-1$.
 * At step $i$, we need access to DP values calculated up to $i-k$.
 * Let $j_{target} = i-k$.
 * We must update the data structures *after* calculating DP for $j_{target}$, so they are ready for $i$.
 *
 * This suggests iterating $i$ from $0$ to $N-1$. We need to manage which DP values are "ready" to be queried.
 *
 * Let $V_{size} = 100001$.
 * $\text{BIT\_Down}[v]$: Stores $\max(\text{dp\_down}[j], \text{nums}[j])$ for all $j$ processed so far such that $\text{nums}[j] = v$ AND $j \le i-k$.
 * $\text{BIT\_Up}[v]$: Stores $\max(\text{dp\_up}[j], \text{nums}[j])$ for all $j$ processed so far such that $\text{nums}[j] = v$ AND $j \le i-k$.
 *
 * To enforce $j \le i-k$: We process $i$ in increasing order. We only add the results from index $j_{add} = i-k$ into the BITs *before* calculating DP for $i$.
 *
 * Implementation Detail:
 * 1. Initialize DP arrays (size N).
 * 2. Initialize two Fenwick Trees (size $V_{size}$).
 * 3. Iterate $i$ from $0$ to $N-1$:
 *    a. Check if $j_{add} = i-k \ge 0$. If so, update $\text{BIT\_Down}$ and $\text{BIT\_Up}$ using $(\text{dp\_down}[j_{add}], \text{nums}[j_{add}])$ and $(\text{dp\_up}[j_{add}], \text{nums}[j_{add}])$ respectively.
 *    b. Calculate $\text{dp\_up}[i]$:
 *       Need $\max(\text{BIT\_Down.query\_prefix}(nums[i]-1), \text{nums}[i])$.
 *       $\text{dp\_up}[i] = \text{nums}[i] + \max(\text{BIT\_Down.query\_prefix}(nums[i]-1), 0)$. (Need careful handling of base case, see below)
 *
 * Let's redefine the stored values in BITs to simplify the base case handling.
 * Let $\text{BIT}_{\text{Down}}[v]$ store $\max(\text{dp\_down}[j], \text{nums}[j])$ for $j$ such that $\text{nums}[j]=v$.
 * The value we query must be the maximum score of a valid previous sequence ending at $j$.
 *
 * If $nums[i] > nums[j]$ (UP swing), the predecessor at $j$ could be:
 *   - A sequence ending with a DOWN swing: score $\text{dp\_down}[j]$.
 *   - A sequence of length 1: score $\text{nums}[j]$.
 * Max predecessor score $P_{down}(i) = \max_{j \le i-k, nums[j] < nums[i]} \{\max(\text{dp\_down}[j], \text{nums}[j])\}$.
 *
 * If we store $\max(\text{dp\_down}[j], \text{nums}[j])$ in $\text{BIT}_{\text{Down}}$ at index $nums[j]$:
 * $P_{down}(i) = \text{BIT}_{\text{Down}}.\text{query\_prefix}(nums[i]-1)$.
 *
 * Similarly, $P_{up}(i) = \text{BIT}_{\text{Up}}.\text{query\_prefix}(V_{max}) \text{ excluding values } \le nums[i]$.
 * $P_{up}(i) = \text{BIT}_{\text{Up}}.\text{query\_range}(nums[i]+1, V_{max})$. (Range query or $\text{BIT}.\text{total} - \text{BIT}.\text{query\_prefix}(nums[i])$).
 *
 * Initial values for DP:
 * $\text{dp\_up}[i] = \text{nums}[i]$ (Base case, length 1)
 * $\text{dp\_down}[i] = \text{nums}[i]$ (Base case, length 1)
 *
 * When calculating $\text{dp\_up}[i]$:
 * $\text{dp\_up}[i] = \max(\text{dp\_up}[i], \text{nums}[i] + P_{down}(i))$
 *
 * When calculating $\text{dp\_down}[i]$:
 * $\text{dp\_down}[i] = \max(\text{dp\_down}[i], \text{nums}[i] + P_{up}(i))$
 *
 * Final result: $\max_{i} (\text{dp\_up}[i], \text{dp\_down}[i])$.
 *
 * This DP with BIT approach is $O(N \log V_{max})$. With $N=10^5, V_{max}=10^5$, this is feasible.
 */

// Max value of nums[i] is 10^5. We use 1-based indexing for BIT up to 100000.
const int MAX_VAL = 100001;

struct FenwickTree {
    vector<long long> tree;
    int size;

    FenwickTree(int n) : size(n), tree(n + 1, 0) {}

    // Update: Sets the value at index idx to max(current_value, val)
    void update(int idx, long long val) {
        for (; idx <= size; idx += idx & -idx) {
            tree[idx] = max(tree[idx], val);
        }
    }

    // Query: Returns max value in prefix [1, idx]
    long long query_prefix(int idx) {
        long long res = 0;
        for (; idx > 0; idx -= idx & -idx) {
            res = max(res, tree[idx]);
        }
        return res;
    }
};

long long solve(std::vector<long long> nums, long long k) {
    int n = nums.size();
    if (n == 0) return 0;

    // dp_up[i]: Max score ending at i, where the last transition was nums[prev] < nums[i] (UP swing)
    // dp_down[i]: Max score ending at i, where the last transition was nums[prev] > nums[i] (DOWN swing)
    vector<long long> dp_up(n);
    vector<long long> dp_down(n);

    // BITs store the maximum potential score from a valid predecessor j, indexed by nums[j].
    // BIT_Down stores max(dp_down[j], nums[j]) for predecessors j where nums[j] < nums[i].
    FenwickTree bit_down(MAX_VAL - 1);
    // BIT_Up stores max(dp_up[j], nums[j]) for predecessors j where nums[j] > nums[i].
