// Let dp_down[i] be the maximum score of a valid alternating subsequence ending at index i,
// where nums[i] is SMALLER than the previous element (i.e., it's a DOWN step: ... > nums[i]).

// Base case: For any single element subsequence, the score is nums[i].
// dp_up[i] = nums[i] (A length 1 sequence can be considered both up or down, but we initialize based on the structure)
// dp_down[i] = nums[i]

long long solve(std::vector<long long> nums, long long k) {
    int n = nums.size();
    if (n == 0) return 0;

    // dp_up[i]: Max score ending at i, where the sequence ends with an increase (a_prev < nums[i])
    std::vector<long long> dp_up(n);
    // dp_down[i]: Max score ending at i, where the sequence ends with a decrease (a_prev > nums[i])
    std::vector<long long> dp_down(n);

    long long max_score = 0;

    for (int i = 0; i < n; ++i) {
        // Base case: A sequence of length 1 always has score nums[i]
        dp_up[i] = nums[i];
        dp_down[i] = nums[i];

        // Transition: Look back at all possible previous indices j such that i - j >= k
        for (int j = 0; j < i - k + 1; ++j) {
            // 1. Transition to dp_up[i] (Current step is UP: nums[j] < nums[i])
            // The previous step ending at j must have been a DOWN step (a_prev > nums[j]).
            if (nums[j] < nums[i]) {
